INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (1, 1.47, "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", 0.0, 10001, "2023/09/22 14:59:59", "2023/06/30 12:00:00", "クローチェ", 1, 1, 2, 126401, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (1, 2.15, "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", 0.0, 10002, "2023/09/22 14:59:59", "2023/06/30 12:00:00", "クローチェ", 2, 2, 1, 126401, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (1, 0.0, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", 0.0, 10003, "2023/09/22 14:59:59", "2023/06/30 12:00:00", "ライラエル", 1, 2, 2, 126501, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (1, 0.0, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", 0.0, 10004, "2023/09/22 14:59:59", "2023/06/30 12:00:00", "ライラエル", 2, 1, 1, 126501, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (2, 0.0, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", 0.0, 10005, "2023/12/22 14:59:59", "2023/09/15 15:00:00", "リンド", 1, 2, 2, 127702, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (2, 0.0, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", 0.0, 10006, "2023/12/22 14:59:59", "2023/09/15 15:00:00", "リンド", 2, 2, 2, 127702, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (2, 0.0, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", 0.0, 10007, "2023/12/22 14:59:59", "2023/09/15 15:00:00", "ヴルム", 1, 1, 1, 127802, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (2, 6.5, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", 0.0, 10008, "2023/12/22 14:59:59", "2023/09/15 15:00:00", "ヴルム", 2, 2, 1, 127802, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (3, 0.0, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", 0.0, 10009, "2024/03/22 14:59:59", "2023/12/15 15:00:00", "アネモネ", 1, 2, 1, 129602, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (3, 0.0, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", 0.0, 10010, "2024/03/22 14:59:59", "2023/12/15 15:00:00", "アネモネ", 2, 2, 1, 129602, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (3, 0.0, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", 0.0, 10011, "2024/03/22 14:59:59", "2023/12/15 15:00:00", "ネフィ=ネラ", 1, 1, 1, 129701, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (3, 6.2, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", 0.0, 10012, "2024/03/22 14:59:59", "2023/12/15 15:00:00", "ネフィ=ネラ", 2, 2, 1, 129701, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (4, 3.1, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", 0.0, 10013, "2024/06/22 14:59:59", "2024/03/15 15:00:00", "カノン", 1, 3, 5, 130301, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (4, 6.15, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", 0.0, 10014, "2024/06/22 14:59:59", "2024/03/15 15:00:00", "カノン", 2, 3, 2, 130301, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (4, 0.0, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", 0.0, 10015, "2024/06/22 14:59:59", "2024/03/15 15:00:00", "ナーナ", 1, 2, 2, 130401, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (4, 3.35, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", 0.0, 10016, "2024/06/22 14:59:59", "2024/03/15 15:00:00", "ナーナ", 2, 2, 1, 130401, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (5, 0.0, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", 0.0, 10017, "2024/09/22 14:59:59", "2024/06/15 15:00:00", "ホウオウ", 1, 1, 1, 130502, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (5, 3.18, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", 0.0, 10018, "2024/09/22 14:59:59", "2024/06/15 15:00:00", "ホウオウ", 2, 2, 1, 130502, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (5, 0.0, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", 0.0, 10019, "2024/09/22 14:59:59", "2024/06/15 15:00:00", "ホウオウ", 3, 4, 4, 130503, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (5, 4.9, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", 0.0, 10020, "2024/09/22 14:59:59", "2024/06/15 15:00:00", "ネア", 1, 1, 2, 123301, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (5, 4.8, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", 0.0, 10021, "2024/09/22 14:59:59", "2024/06/15 15:00:00", "ネア", 2, 1, 2, 123301, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (6, 4.922, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", 0.0, 10022, "2024/12/22 14:59:59", "2024/09/15 15:00:00", "カリザ", 1, 3, 1, 133301, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (6, 9.638, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", 0.0, 10023, "2024/12/22 14:59:59", "2024/09/15 15:00:00", "カリザ", 2, 3, 5, 133301, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (6, 2.88, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", 0.0, 10024, "2024/12/22 14:59:59", "2024/09/15 15:00:00", "ミーア", 1, 1, 2, 133401, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (6, 4.818, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", 0.0, 10025, "2024/12/22 14:59:59", "2024/09/15 15:00:00", "ミーア", 2, 5, 1, 133401, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (7, 1.78, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", 0.0, 10026, "2025/03/22 14:59:59", "2024/12/15 15:00:00", "グレイス", 1, 2, 1, 133002, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (7, 6.15, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", 0.0, 10027, "2025/03/22 14:59:59", "2024/12/15 15:00:00", "グレイス", 2, 1, 7, 133002, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (7, 4.28, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", 0.0, 10028, "2025/03/22 14:59:59", "2024/12/15 15:00:00", "ヴァイオレット", 1, 6, 2, 133102, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (7, 0.0, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", 0.0, 10029, "2025/03/22 14:59:59", "2024/12/15 15:00:00", "ヴァイオレット", 2, 1, 1, 133102, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (8, 5.53, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", 0.0, 10030, "2025/06/23 14:59:59", "2025/03/15 15:00:00", "ルルィ", 1, 2, 1, 136902, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (8, 6.05, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", 0.0, 10031, "2025/06/23 14:59:59", "2025/03/15 15:00:00", "ルルィ", 2, 9, 7, 136902, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (8, 0.0, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", 0.0, 10032, "2025/06/23 14:59:59", "2025/03/15 15:00:00", "デュラン", 1, 2, 1, 137001, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (8, 0.0, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", 0.0, 10033, "2025/06/23 14:59:59", "2025/03/15 15:00:00", "デュラン", 2, 2, 1, 137001, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (9, 0.0, "おう\n好きなもん持ってきな", 0.0, 10034, "2025/09/23 14:59:59", "2025/06/16 15:00:00", "サツキ", 1, 2, 2, 135902, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (9, 4.935, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", 0.0, 10035, "2025/09/23 14:59:59", "2025/06/16 15:00:00", "サツキ", 2, 1, 6, 135902, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (9, 7.441, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", 0.0, 10036, "2025/09/23 14:59:59", "2025/06/16 15:00:00", "ユキノ", 1, 2, 5, 135802, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (9, 0.0, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", 0.0, 10037, "2025/09/23 14:59:59", "2025/06/16 15:00:00", "ユキノ", 2, 7, 7, 135802, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (10, 2.295, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", 0.0, 10038, "2025/12/22 14:59:59", "2025/09/16 15:00:00", "クルル", 1, 2, 2, 130901, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (10, 6.281, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", 0.0, 10039, "2025/12/22 14:59:59", "2025/09/16 15:00:00", "クルル", 2, 1, 6, 130901, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (10, 5.549, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", 0.0, 10040, "2025/12/22 14:59:59", "2025/09/16 15:00:00", "ヴォルガーノ", 1, 2, 1, 137701, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (10, 2.64, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", 0.0, 10041, "2025/12/22 14:59:59", "2025/09/16 15:00:00", "ヴォルガーノ", 2, 3, 6, 137701, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (11, 7.642, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", 0.0, 10042, "2026/03/23 11:59:59", "2025/12/15 15:00:00", "ライラエル", 1, 7, 4, 132801, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (11, 0.0, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", 0.0, 10043, "2026/03/23 11:59:59", "2025/12/15 15:00:00", "ライラエル", 2, 1, 1, 132802, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (11, 0.0, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", 0.0, 10044, "2026/03/23 11:59:59", "2025/12/15 15:00:00", "クローチェ", 1, 1, 1, 134502, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (11, 3.72, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", 0.0, 10045, "2026/03/23 11:59:59", "2025/12/15 15:00:00", "クローチェ", 2, 2, 1, 134501, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (12, 4.991, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", 0.0, 10046, "2026/06/22 11:59:59", "2026/03/16 12:00:00", "ネフィ＝ネラ", 1, 2, 1, 138201, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (12, 3.877, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", 0.0, 10047, "2026/06/22 11:59:59", "2026/03/16 12:00:00", "ネフィ＝ネラ", 2, 1, 4, 138201, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (12, 1.71, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", 0.0, 10048, "2026/06/22 11:59:59", "2026/03/16 12:00:00", "アラクネ", 1, 4, 6, 136001, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (12, 5.32, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", 0.0, 10049, "2026/06/22 11:59:59", "2026/03/16 12:00:00", "アラクネ", 2, 5, 2, 136001, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (13, 3.727, "水着で、店番とか──\n本当、意味がわかりません\n海の家でもないのに…", 0.0, 10050, "2026/09/22 11:59:59", "2026/06/15 12:00:00", "アネモネ", 1, 9, 4, 135401, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (13, 7.213, "──リアみたいに、\nもっと愛想良い接客を…\nいえ──なんでもないです", 0.0, 10051, "2026/09/22 11:59:59", "2026/06/15 12:00:00", "アネモネ", 2, 7, 9, 135401, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (13, 1.874, "いらっしゃいませー♪\n奉仕活動兼、将来のために\nたくさん働いちゃいます♪", 0.0, 10052, "2026/09/22 11:59:59", "2026/06/15 12:00:00", "クリア", 1, 1, 2, 135301, -470.0, 2002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (13, 0.0, "アルバイトが終わったら\n海に遊びに行きましょう！\nモネちゃんも一緒に♪", 0.0, 10053, "2026/09/22 11:59:59", "2026/06/15 12:00:00", "クリア", 2, 2, 2, 135301, -470.0, 2002);
